--changeset system:006-remove-seed-accounts
-- Remove the demo/mock accounts seeded in 004_seed_data.sql.
-- Real users are now provisioned just-in-time from their Auth0 identity, so the
-- hard-coded sample accounts are no longer needed. Dependents are removed first
-- because the account FKs are not declared ON DELETE CASCADE.
DELETE FROM bookings WHERE account_id IN (
    'a1000000-0000-0000-0000-000000000001',
    'a1000000-0000-0000-0000-000000000002',
    'a1000000-0000-0000-0000-000000000003',
    'a1000000-0000-0000-0000-000000000004',
    'a1000000-0000-0000-0000-000000000005',
    'a1000000-0000-0000-0000-000000000006',
    'a1000000-0000-0000-0000-000000000007'
);

